import React, { useEffect, useState } from "react";
import { Line } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
} from "chart.js";
import { Eye, BarChart3, Volume2, Activity } from "lucide-react";

import CompanyItem from "../Compontes/CompanyItem";
import MetricCard from "../Compontes/";
import AIPrediction from "../components/AIPrediction";
import WelcomeMessage from "../components/WelcomeMessage";
import { fetchCompanies, fetchStockData } from "../utils/api";

ChartJS.register(CategoryScale, LinearScale, PointElement, LineElement, Title, Tooltip, Legend, Filler);

const StockDashboard = () => {
  const [companies, setCompanies] = useState([]);
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [stockData, setStockData] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  // Fetch company list from backend
  useEffect(() => {
    fetchCompanies()
      .then(setCompanies)
      .catch((err) => console.error("Error fetching companies:", err));
  }, []);

  // Fetch stock data for selected company
  const handleCompanySelect = async (company) => {
    setSelectedCompany(company);
    setIsLoading(true);
    try {
      const data = await fetchStockData(company.id);
      setStockData(data);
    } catch (err) {
      console.error("Error fetching stock data:", err);
      setStockData([]);
    } finally {
      setIsLoading(false);
    }
  };

  // Filter companies for search
  const filteredCompanies = companies.filter(
    (c) =>
      c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
      c.symbol.toLowerCase().includes(searchTerm.toLowerCase())
  );

  // ChartJS data
  const chartData = selectedCompany
    ? {
        labels: stockData.map((d) => d.date),
        datasets: [
          {
            data: stockData.map((d) => Number(d.close ?? 0)),
            borderColor: "#3b82f6",
            backgroundColor: "rgba(59, 130, 246, 0.08)",
            fill: true,
          },
        ],
      }
    : null;

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { display: false },
      tooltip: { mode: "index", intersect: false },
    },
    interaction: { mode: "nearest", intersect: false },
    scales: {
      x: { display: true, title: { display: true, text: "Date" } },
      y: { display: true, title: { display: true, text: "Price (₹)" } },
    },
  };

  return (
    <div className="flex h-screen bg-gradient-to-br from-slate-50 to-blue-50">
      {/* Sidebar */}
      <div className="w-96 bg-white shadow-2xl border-r border-gray-200 flex flex-col">
        <div className="p-6 bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 text-white">
          <h1 className="text-xl font-bold">StockVision</h1>
        </div>

        <div className="p-4 border-b border-gray-100">
          <input
            type="text"
            placeholder="Search companies..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-4 pr-4 py-2 border rounded-2xl"
          />
        </div>

        <div className="flex-1 overflow-y-auto py-2">
          {filteredCompanies.length > 0 ? (
            filteredCompanies.map((company) => (
              <CompanyItem
                key={company.id}
                company={company}
                isActive={selectedCompany?.id === company.id}
                onClick={() => handleCompanySelect(company)}
              />
            ))
          ) : (
            <p className="text-center text-gray-400 mt-6">No companies found</p>
          )}
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 p-6 overflow-y-auto space-y-6">
        {!selectedCompany && <WelcomeMessage />}

        {selectedCompany && (
          <>
            {/* Metrics */}
            <div className="grid grid-cols-4 gap-6 mb-6">
              <MetricCard label="Current Price" value={`₹${selectedCompany.currentPrice}`} icon={BarChart3} />
              <MetricCard label="Volume" value={selectedCompany.volume} icon={Volume2} />
              <MetricCard label="P/E Ratio" value={selectedCompany.pe} icon={Eye} />
              <MetricCard label="Market Cap" value={selectedCompany.marketCap} icon={Activity} />
            </div>

            {/* Chart */}
            <div className="bg-white p-6 rounded-2xl shadow-lg">
              <h3 className="text-lg font-bold mb-4">{selectedCompany.name} Stock Chart</h3>
              {isLoading ? (
                <p className="text-gray-400">Loading chart...</p>
              ) : chartData ? (
                <Line data={chartData} options={chartOptions} height={200} />
              ) : (
                <p className="text-gray-400">No stock data available</p>
              )}
            </div>

            {/* AI Prediction */}
            <AIPrediction company={selectedCompany} isLoading={isLoading} />
          </>
        )}
      </div>
    </div>
  );
};

export default StockDashboard;
